readonly class Result {
    private function __construct(
        public mixed $value,
        public ?string $error,
        public bool $ok,
    ) {}
    public static function ok(mixed $v): self { return new self($v, null, true); }
    public static function err(string $e): self { return new self(null, $e, false); }
}

function findUser(int $id): Result {
    $user = User::find($id);
    return $user ? Result::ok($user) : Result::err("User $id not found");
}

$r = findUser(42);
echo match(true) {
    $r->ok  => "Found: {$r->value->name}",
    default => "Error: {$r->error}",
};

